import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import Header from './Header';
import 'bootstrap/dist/css/bootstrap.min.css';
import '@fortawesome/fontawesome-free/css/all.min.css';

// Route: /upload-rfid -> UploadRFID component (Excel file upload for RFID data)

const RFIDIntegration = () => {
  const [userInfo, setUserInfo] = useState({});

  useEffect(() => {
    const userInfo = JSON.parse(localStorage.getItem('userInfo')) || {};
    setUserInfo(userInfo);
  }, []);

  // Common style objects
  const buttonHoverStyles = {
    transform: 'translateY(-2px)',
    boxShadow: '0 6px 20px rgba(84, 112, 255, 0.4)'
  };

  const buttonResetStyles = {
    transform: 'translateY(0)',
    boxShadow: '0 4px 14px rgba(84, 112, 255, 0.3)'
  };

  return (
    <div style={{
      display: 'flex',
      flexDirection: 'column',
      height: '100vh',
      overflow: 'hidden',
      background: 'linear-gradient(135deg, #f8f9fa 0%, #ececec 100%)'
    }}>
      <Header userInfo={userInfo} />
      
      <div
        className="hide-scrollbar"
        style={{
          flex: 1,
          overflowY: 'auto',
          background: 'none',
          paddingBottom: '2rem'
        }}
      >
        <div className="container py-5">
          <div className="text-center mb-5">
            <div style={{ 
              width: 90,
              height: 90,
              background: 'linear-gradient(90deg, #0078d4 0%, #d60000 100%)',
              borderRadius: '50%',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              margin: '0 auto 1.5rem',
              boxShadow: '0 8px 24px #0078d422',
            }}>
              <i className="fas fa-plug fa-3x" style={{ color: 'white' }}></i>
            </div>
            <h1 className="mb-3 fw-bold" style={{ 
              fontSize: '2.4rem', 
              color: '#0078d4', 
              letterSpacing: 0.5,
              background: 'linear-gradient(90deg, #0078d4 0%, #d60000 100%)',
              WebkitBackgroundClip: 'text',
              WebkitTextFillColor: 'transparent'
            }}>
              RFID Integration
            </h1>
            <p className="lead mb-5" style={{ 
              fontSize: '1.2rem', 
              color: '#555', 
              maxWidth: '800px', 
              margin: '0 auto' 
            }}>
              Follow these steps to seamlessly integrate RFID technology with your existing systems.
            </p>
          </div>
          
          {/* Reusable Tag Section */}
          <div className="card mb-4 border-0 shadow-sm rfid-card rfid-card-reusable" style={{ position: 'relative', borderRadius: '22px', overflow: 'hidden', transition: 'box-shadow 0.2s, transform 0.2s', background: 'linear-gradient(135deg, #e3f0ff 0%, #fafdff 60%, #d1eaff 100%)', boxShadow: '0 10px 32px #b3d8ff44, 0 2px 8px #b3d8ff22' }}>
            {/* Step Number Badge */}
            <div style={{
              position: 'absolute',
              left: 18,
              top: -22,
              zIndex: 3,
              width: 54,
              height: 54,
              background: 'linear-gradient(135deg, #5470FF 0%, #6C8FFF 100%)',
              color: '#fff',
              borderRadius: '50%',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              fontSize: 28,
              fontWeight: 900,
              fontFamily: 'Poppins, Inter, sans-serif',
              boxShadow: '0 4px 16px #5470ff55',
              border: '3px solid #fff',
              letterSpacing: 0.1
            }}>1</div>
            {/* Accent Bar */}
            <div style={{
              position: 'absolute',
              left: 0,
              top: 0,
              bottom: 0,
              width: 10,
              background: 'linear-gradient(180deg, #5470FF 0%, #6C8FFF 100%)',
              borderTopLeftRadius: 22,
              borderBottomLeftRadius: 22,
              boxShadow: '0 0 16px #5470ff55',
              zIndex: 1
            }}></div>
            <div className="card-body p-4" style={{ borderRadius: '22px', border: '1.5px solid #b3d8ff', background: 'none', position: 'relative', zIndex: 2 }}>
              <div className="d-flex align-items-center mb-3">
                <div className="pulse-icon" style={{
                  width: 54,
                  height: 54,
                  background: 'linear-gradient(45deg, #5470FF, #6C8FFF, #a8e0ff)',
                  borderRadius: '50%',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  marginRight: '20px',
                  boxShadow: '0 0 20px #5470ff88, 0 2px 8px #b3d8ff44',
                  border: '3px solid #fff',
                  animation: 'pulse 1.8s infinite',
                }}>
                  <i className="fas fa-redo" style={{ color: '#fff', fontSize: 30, textShadow: '0 0 10px #5470ff88' }}></i>
                </div>
                <h4 className="mb-0 fw-bold" style={{ color: '#2a4d9c', fontFamily: 'Poppins, Inter, sans-serif', fontWeight: 900, fontSize: '1.55rem', letterSpacing: 0.2 }}>Reusable Tag</h4>
              </div>
              <ul style={{ fontSize: '1.12rem', color: '#333', marginLeft: 10, fontFamily: 'Inter, sans-serif', paddingLeft: 0 }}>
                <li style={{ display: 'flex', alignItems: 'center', marginBottom: 8 }}>
                  <span style={{ background: 'linear-gradient(135deg, #6C8FFF 0%, #b3d8ff 100%)', color: '#fff', borderRadius: '50%', width: 28, height: 28, display: 'flex', alignItems: 'center', justifyContent: 'center', marginRight: 12 }}><i className="fas fa-keyboard"></i></span>
                  To use the reusable tags in your software system, we need one text box like RFID code or RFID no.
                </li>
                <li style={{ display: 'flex', alignItems: 'center', marginBottom: 8 }}>
                  <span style={{ background: 'linear-gradient(135deg, #6C8FFF 0%, #b3d8ff 100%)', color: '#fff', borderRadius: '50%', width: 28, height: 28, display: 'flex', alignItems: 'center', justifyContent: 'center', marginRight: 12 }}><i className="fas fa-qrcode"></i></span>
                  While you do the stock entry, at that time our RFID no has to be scanned (QR code) or the RFID number typed.
                </li>
                <li style={{ display: 'flex', alignItems: 'center', marginBottom: 8 }}>
                  <span style={{ background: 'linear-gradient(135deg, #6C8FFF 0%, #b3d8ff 100%)', color: '#fff', borderRadius: '50%', width: 28, height: 28, display: 'flex', alignItems: 'center', justifyContent: 'center', marginRight: 12 }}><i className="fas fa-link"></i></span>
                  So our RFID number will pair with your item code.
                </li>
                <li style={{ display: 'flex', alignItems: 'center', marginBottom: 8 }}>
                  <span style={{ background: 'linear-gradient(135deg, #6C8FFF 0%, #b3d8ff 100%)', color: '#fff', borderRadius: '50%', width: 28, height: 28, display: 'flex', alignItems: 'center', justifyContent: 'center', marginRight: 12 }}><i className="fas fa-edit"></i></span>
                  In existing stocks, customers can edit or put the RFID number in the inventory list.
                </li>
                <li style={{ display: 'flex', alignItems: 'center', marginBottom: 8 }}>
                  <span style={{ background: 'linear-gradient(135deg, #6C8FFF 0%, #b3d8ff 100%)', color: '#fff', borderRadius: '50%', width: 28, height: 28, display: 'flex', alignItems: 'center', justifyContent: 'center', marginRight: 12 }}><i className="fas fa-file-excel"></i></span>
                  For existing stocks, customers can prepare an Excel sheet of matching RFID code and item code.
                </li>
              </ul>
            </div>
          </div>

          {/* Single Time Use Tag Section */}
          <div className="card mb-4 border-0 shadow-sm rfid-card rfid-card-single" style={{ position: 'relative', borderRadius: '22px', overflow: 'hidden', transition: 'box-shadow 0.2s, transform 0.2s', background: 'linear-gradient(135deg, #fffbe3 0%, #fff3b3 60%, #ffe5b3 100%)', boxShadow: '0 10px 32px #ffe5b344, 0 2px 8px #ffe5b322' }}>
            {/* Step Number Badge */}
            <div style={{
              position: 'absolute',
              left: 18,
              top: -22,
              zIndex: 3,
              width: 54,
              height: 54,
              background: 'linear-gradient(135deg, #FF9966 0%, #FF5E62 100%)',
              color: '#fff',
              borderRadius: '50%',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              fontSize: 28,
              fontWeight: 900,
              fontFamily: 'Poppins, Inter, sans-serif',
              boxShadow: '0 4px 16px #ff996655',
              border: '3px solid #fff',
              letterSpacing: 0.1
            }}>2</div>
            {/* Accent Bar */}
            <div style={{
              position: 'absolute',
              left: 0,
              top: 0,
              bottom: 0,
              width: 10,
              background: 'linear-gradient(180deg, #FF9966 0%, #FF5E62 100%)',
              borderTopLeftRadius: 22,
              borderBottomLeftRadius: 22,
              boxShadow: '0 0 16px #ff996655',
              zIndex: 1
            }}></div>
            <div className="card-body p-4" style={{ borderRadius: '22px', border: '1.5px solid #ffe5b3', background: 'none', position: 'relative', zIndex: 2 }}>
              <div className="d-flex align-items-center mb-3">
                <div className="pulse-icon" style={{
                  width: 54,
                  height: 54,
                  background: 'linear-gradient(45deg, #FF9966, #FF5E62, #ffe5b3)',
                  borderRadius: '50%',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  marginRight: '20px',
                  boxShadow: '0 0 20px #ff996688, 0 2px 8px #ffe5b344',
                  border: '3px solid #fff',
                  animation: 'pulse 1.8s infinite',
                }}>
                  <i className="fas fa-tag" style={{ color: '#fff', fontSize: 30, textShadow: '0 0 10px #ff996688' }}></i>
                </div>
                <h4 className="mb-0 fw-bold" style={{ color: '#bfa100', fontFamily: 'Poppins, Inter, sans-serif', fontWeight: 900, fontSize: '1.55rem', letterSpacing: 0.2 }}>Single Time Use Tag</h4>
              </div>
              <ul style={{ fontSize: '1.12rem', color: '#333', marginLeft: 10, fontFamily: 'Inter, sans-serif', paddingLeft: 0 }}>
                <li style={{ display: 'flex', alignItems: 'center', marginBottom: 8 }}>
                  <span style={{ background: 'linear-gradient(135deg, #FF9966 0%, #FF5E62 100%)', color: '#fff', borderRadius: '50%', width: 28, height: 28, display: 'flex', alignItems: 'center', justifyContent: 'center', marginRight: 12 }}><i className="fas fa-print"></i></span>
                  Single time use tags can be printed or encoded using an RFID printer.
                </li>
                <li style={{ display: 'flex', alignItems: 'center', marginBottom: 8 }}>
                  <span style={{ background: 'linear-gradient(135deg, #FF9966 0%, #FF5E62 100%)', color: '#fff', borderRadius: '50%', width: 28, height: 28, display: 'flex', alignItems: 'center', justifyContent: 'center', marginRight: 12 }}><i className="fas fa-barcode"></i></span>
                  The RFID printer converts an item code or barcode value to a hexadecimal number.
                </li>
                <li style={{ display: 'flex', alignItems: 'center', marginBottom: 8 }}>
                  <span style={{ background: 'linear-gradient(135deg, #FF9966 0%, #FF5E62 100%)', color: '#fff', borderRadius: '50%', width: 28, height: 28, display: 'flex', alignItems: 'center', justifyContent: 'center', marginRight: 12 }}><i className="fas fa-sort-numeric-up"></i></span>
                  The hexadecimal number should be a multiple of four.
                </li>
                <li style={{ display: 'flex', alignItems: 'center', marginBottom: 8 }}>
                  <span style={{ background: 'linear-gradient(135deg, #FF9966 0%, #FF5E62 100%)', color: '#fff', borderRadius: '50%', width: 28, height: 28, display: 'flex', alignItems: 'center', justifyContent: 'center', marginRight: 12 }}><i className="fas fa-plus-square"></i></span>
                  If the hexadecimal code is not a multiple of four, the printer adds "00" at the start or end of the hex code.
                </li>
                <li style={{ display: 'flex', alignItems: 'center', marginBottom: 8 }}>
                  <span style={{ background: 'linear-gradient(135deg, #FF9966 0%, #FF5E62 100%)', color: '#fff', borderRadius: '50%', width: 28, height: 28, display: 'flex', alignItems: 'center', justifyContent: 'center', marginRight: 12 }}><i className="fas fa-check-circle"></i></span>
                  If the exact hexadecimal code matches, the RFID inventory will be scanned.
                </li>
              </ul>
            </div>
          </div>

          {/* Add hover and pulse effect for cards and icons */}
          <style>{`
            .rfid-card:hover {
              box-shadow: 0 16px 40px #b3d8ff55, 0 2px 8px #b3d8ff22;
              transform: translateY(-4px) scale(1.018);
            }
            .rfid-card-single:hover {
              box-shadow: 0 16px 40px #ffe5b355, 0 2px 8px #ffe5b322;
            }
            @keyframes pulse {
              0% { box-shadow: 0 0 0 0 rgba(84,112,255,0.18), 0 0 20px #5470ff88; }
              70% { box-shadow: 0 0 0 12px rgba(84,112,255,0.04), 0 0 20px #5470ff44; }
              100% { box-shadow: 0 0 0 0 rgba(84,112,255,0.18), 0 0 20px #5470ff88; }
            }
            .rfid-card-single .pulse-icon {
              animation: pulse 1.8s infinite;
              box-shadow: 0 0 20px #ff996688, 0 2px 8px #ffe5b344;
            }
            .rfid-card-reusable .pulse-icon {
              animation: pulse 1.8s infinite;
              box-shadow: 0 0 20px #5470ff88, 0 2px 8px #b3d8ff44;
            }
          `}</style>

          <div className="text-center mt-5">
            <div style={{ margin: '2rem auto', maxWidth: '600px' }}>
              <p className="mb-4" style={{ fontSize: '1.1rem', color: '#555' }}>
                For detailed API documentation and testing tools, please refer to the Dashboard page.
              </p>
              <Link 
                to="/dashboard" 
                className="btn px-5 py-3 fw-bold"
                style={{
                  fontSize: '1.1rem',
                  background: 'linear-gradient(45deg, #5470FF, #6C8FFF)',
                  color: '#fff',
                  border: 'none',
                  borderRadius: 14,
                  boxShadow: '0 4px 14px rgba(84, 112, 255, 0.3)',
                  transition: 'all 0.3s'
                }}
                onMouseOver={(e) => {
                  e.currentTarget.style.background = 'linear-gradient(45deg, #4560EB, #5A7DF0)';
                  Object.assign(e.currentTarget.style, buttonHoverStyles);
                }}
                onMouseOut={(e) => {
                  e.currentTarget.style.background = 'linear-gradient(45deg, #5470FF, #6C8FFF)';
                  Object.assign(e.currentTarget.style, buttonResetStyles);
                }}
              >
                <i className="fas fa-arrow-left me-2"></i>
                Back to Dashboard
              </Link>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default RFIDIntegration;
